    12→    --font-noto-serif-jp: var(--font-noto-serif-jp);
    13→    --color-background-warm: var(--background-warm);
    14→    --color-gold: var(--gold);
    15→    --color-gold-dim: var(--gold-dim);
    16→    --color-teal: var(--teal);
    17→    --color-sidebar-ring: var(--sidebar-ring);
    18→    --color-sidebar-border: var(--sidebar-border);
    19→    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    20→    --color-sidebar-accent: var(--sidebar-accent);
    21→    --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
    22→    --color-sidebar-primary: var(--sidebar-primary);
    23→    --color-sidebar-foreground: var(--sidebar-foreground);
    24→    --color-sidebar: var(--sidebar);
    25→    --color-chart-5: var(--chart-5);
    26→    --color-chart-4: var(--chart-4);
    27→    --color-chart-3: var(--chart-3);
    28→    --color-chart-2: var(--chart-2);
    29→    --color-chart-1: var(--chart-1);
    30→    --color-ring: var(--ring);
    31→    --color-input: var(--input);
    32→    --color-border: var(--border);
    33→    --color-destructive: var(--destructive);
    34→    --color-accent-foreground: var(--accent-foreground);
    35→    --color-accent: var(--accent);
    36→    --color-muted-foreground: var(--muted-foreground);
    37→    --color-muted: var(--muted);
    38→    --color-secondary-foreground: var(--secondary-foreground);
    39→    --color-secondary: var(--secondary);
    40→    --color-primary-foreground: var(--primary-foreground);
    41→    --color-primary: var(--primary);
    42→    --color-popover-foreground: var(--popover-foreground);
    43→    --color-popover: var(--popover);
    44→    --color-card-foreground: var(--card-foreground);
    45→    --color-card: var(--card);
    46→    --color-foreground: var(--foreground);
    47→    --color-background: var(--background);
    48→    --radius-sm: calc(var(--radius) * 0.6);
    49→    --radius-md: calc(var(--radius) * 0.8);
    50→    --radius-lg: var(--radius);
    51→    --radius-xl: calc(var(--radius) * 1.4);
    52→    --radius-2xl: calc(var(--radius) * 1.8);
    53→    --radius-3xl: calc(var(--radius) * 2.2);
    54→    --radius-4xl: calc(var(--radius) * 2.6);
    55→}
    56→
    57→:root {
    58→    /* JukuBox.ai — Warm Retro Chic */
    59→    /* システム共通デザイントークン（shadcn 変数を上書き） */
    60→    --background: oklch(0.10 0.015 50);
    61→    --foreground: oklch(0.90 0.03 78);
    62→    --card: oklch(0.17 0.02 50 / 0.9);
    63→    --card-foreground: oklch(0.90 0.03 78);
    64→    --popover: oklch(0.17 0.02 50 / 0.9);
    65→    --popover-foreground: oklch(0.90 0.03 78);
    66→    --muted-foreground: oklch(0.72 0.025 55);
    67→    --border: oklch(1 0 0 / 0.15);
    68→    --input: oklch(1 0 0 / 0.07);
    69→    /* shadcn に対応がないシステム共通トークン */
    70→    --background-warm: oklch(0.13 0.02 50);
    71→    --gold: oklch(0.75 0.12 77);
    72→    --gold-dim: oklch(0.50 0.08 77);
    73→    --teal: oklch(0.72 0.09 190);
    74→    --grid-line: oklch(0.75 0.12 77 / 0.04);
    75→    --primary: oklch(0.205 0 0);
    76→    --primary-foreground: oklch(0.985 0 0);
    77→    --secondary: oklch(0.97 0 0);
    78→    --secondary-foreground: oklch(0.205 0 0);
    79→    --muted: oklch(0.269 0 0);
    80→    --accent: oklch(0.269 0 0);
    81→    --accent-foreground: oklch(0.985 0 0);
    82→    --destructive: oklch(0.577 0.245 27.325);
    83→    --ring: oklch(0.708 0 0);
    84→    --chart-1: oklch(0.87 0 0);
    85→    --chart-2: oklch(0.556 0 0);
    86→    --chart-3: oklch(0.439 0 0);
    87→    --chart-4: oklch(0.371 0 0);
    88→    --chart-5: oklch(0.269 0 0);
    89→    --radius: 0.625rem;
    90→    --sidebar: oklch(0.985 0 0);
    91→    --sidebar-foreground: oklch(0.145 0 0);
    92→    --sidebar-primary: oklch(0.205 0 0);
    93→    --sidebar-primary-foreground: oklch(0.985 0 0);
    94→    --sidebar-accent: oklch(0.97 0 0);
    95→    --sidebar-accent-foreground: oklch(0.205 0 0);
    96→    --sidebar-border: oklch(0.922 0 0);
    97→    --sidebar-ring: oklch(0.708 0 0);
    98→}
    99→
   100→.dark {
   101→    --background: oklch(0.145 0 0);
   102→    --foreground: oklch(0.985 0 0);
   103→    --card: oklch(0.205 0 0);
   104→    --card-foreground: oklch(0.985 0 0);
   105→    --popover: oklch(0.205 0 0);
   106→    --popover-foreground: oklch(0.985 0 0);
   107→    --primary: oklch(0.922 0 0);
   108→    --primary-foreground: oklch(0.205 0 0);
   109→    --secondary: oklch(0.269 0 0);
   110→    --secondary-foreground: oklch(0.985 0 0);
   111→    --muted: oklch(0.269 0 0);
   112→    --muted-foreground: oklch(0.708 0 0);
   113→    --accent: oklch(0.269 0 0);
   114→    --accent-foreground: oklch(0.985 0 0);
   115→    --destructive: oklch(0.704 0.191 22.216);
   116→    --border: oklch(1 0 0 / 10%);
   117→    --input: oklch(1 0 0 / 15%);
   118→    --ring: oklch(0.556 0 0);
   119→    --chart-1: oklch(0.87 0 0);
   120→    --chart-2: oklch(0.556 0 0);
   121→    --chart-3: oklch(0.439 0 0);
   122→    --chart-4: oklch(0.371 0 0);
   123→    --chart-5: oklch(0.269 0 0);
   124→    --sidebar: oklch(0.205 0 0);
   125→    --sidebar-foreground: oklch(0.985 0 0);
   126→    --sidebar-primary: oklch(0.488 0.243 264.376);
   127→    --sidebar-primary-foreground: oklch(0.985 0 0);
   128→    --sidebar-accent: oklch(0.269 0 0);
   129→    --sidebar-accent-foreground: oklch(0.985 0 0);
   130→    --sidebar-border: oklch(1 0 0 / 10%);
   131→    --sidebar-ring: oklch(0.556 0 0);
   132→}
   133→
   134→@layer base {
   135→  * {
   136→    @apply border-border outline-ring/50;
   137→    }
   138→  body {
   139→    @apply bg-background text-foreground;
   140→    }
   141→  html {
   142→    @apply font-sans;
   143→    }
   144→}
   145→
   146→/* フィルムグレイン質感 */
   147→body::after {
   148→  content: '';
   149→  position: fixed;
   150→  inset: 0;
   151→  background-image: url("data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/><feColorMatrix type='saturate' values='0'/></filter><rect width='200' height='200' filter='url(%23n)' opacity='0.18'/></svg>");
   152→  opacity: 0.055;
   153→  pointer-events: none;
   154→  z-index: 9000;
   155→  mix-blend-mode: overlay;
   156→}
   157→
   158→@keyframes juku-record-spin {
   159→  from { transform: rotate(0deg); }
   160→  to { transform: rotate(360deg); }
   161→}
   162→
   163→@keyframes juku-breathe {
   164→  0%, 100% { opacity: 0.85; }
   165→  50% { opacity: 1; }
   166→}
   167→
   168→@keyframes juku-glow-gold {
   169→  0%, 100% {
   170→    box-shadow: 0 0 8px var(--gold-dim), 0 0 16px oklch(0.75 0.12 77 / 0.2);
   171→  }
   172→  50% {
   173→    box-shadow: 0 0 12px var(--gold), 0 0 28px oklch(0.75 0.12 77 / 0.25);
   174→  }
   175→}
